const items = $input.all();
const hoy = new Date();
const en3dias = new Date();
en3dias.setDate(hoy.getDate() + 3);

const proximos = [];

for (const item of items) {
  const partes = item.json.fecha.split('/');
  if (partes.length !== 3) continue;

  const fecha = new Date(partes[2], partes[1] - 1, partes[0]);

  if (fecha >= hoy && fecha <= en3dias) {
    const diasRestantes = Math.ceil((fecha - hoy) / (1000 * 60 * 60 * 24));
    let urgencia = '';
    if (diasRestantes === 0) urgencia = 'HOY';
    else if (diasRestantes === 1) urgencia = 'MANANA';
    else urgencia = `En ${diasRestantes} dias`;

    proximos.push({
      json: {
        ...item.json,
        dias_restantes: diasRestantes,
        urgencia: urgencia,
        hay_eventos: true
      }
    });
  }
}

if (proximos.length === 0) {
  return [{ json: { hay_eventos: false } }];
}

return proximos;

